BEGIN;
--
-- Create model NYCoADocketEntry
--
CREATE TABLE "search_nycoadocketentry" ("id" integer NOT NULL PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY, "date_created" timestamp with time zone NOT NULL, "date_modified" timestamp with time zone NOT NULL, "page" integer NOT NULL, "filing_type" text NOT NULL, "party" text NOT NULL, "date_received" date NULL, "sequence_number" varchar(16) NOT NULL, "docket_id" integer NOT NULL);
COMMENT ON COLUMN "search_nycoadocketentry"."page" IS 'The Court-PASS page this entry was scraped from. Entries are numbered independently per page, so two entries from different pages can share a ``sequence_number``; ``page`` is therefore part of the natural key.';
COMMENT ON COLUMN "search_nycoadocketentry"."filing_type" IS 'The filing type from the Court-PASS FILINGS table (e.g. "Appellant Brief"). Blank for entries that only carry a document.';
COMMENT ON COLUMN "search_nycoadocketentry"."party" IS 'The party associated with the filing, if any.';
COMMENT ON COLUMN "search_nycoadocketentry"."date_received" IS 'The date Court-PASS recorded the filing as received.';
COMMENT ON COLUMN "search_nycoadocketentry"."sequence_number" IS 'CL-generated field to keep entries in a stable order. Concatenation of a filing date (in ISO format) and the entry''s per-page index, mirroring the convention used for Texas dockets.';
COMMENT ON COLUMN "search_nycoadocketentry"."docket_id" IS 'The Docket this entry is associated with.';
--
-- Create model NYCoADocketMetadata
--
CREATE TABLE "search_nycoadocketmetadata" ("id" integer NOT NULL PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY, "date_created" timestamp with time zone NOT NULL, "date_modified" timestamp with time zone NOT NULL, "issue" text NOT NULL, "summary" text NOT NULL, "decision_date" date NULL, "opinion_by" text NULL, "official_citation" varchar(255) NULL, "docket_id" integer NOT NULL UNIQUE);
--
-- Create model NYCoADocument
--
CREATE TABLE "search_nycoadocument" ("id" integer NOT NULL PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY, "date_created" timestamp with time zone NOT NULL, "date_modified" timestamp with time zone NOT NULL, "sha1" varchar(40) NOT NULL, "page_count" integer NULL, "file_size" integer NULL, "filepath_local" varchar(1000) NOT NULL, "filepath_ia" varchar(1000) NOT NULL, "ia_upload_failure_count" smallint NULL, "thumbnail" varchar(100) NULL, "thumbnail_status" smallint NOT NULL, "plain_text" text NOT NULL, "ocr_status" smallint NULL, "file_name" text NOT NULL, "document_number" integer NOT NULL, "available" boolean NOT NULL, "docket_entry_id" integer NOT NULL);
COMMENT ON COLUMN "search_nycoadocument"."file_name" IS 'The filename as shown on the Court-PASS filing-detail page.';
COMMENT ON COLUMN "search_nycoadocument"."document_number" IS 'The 1-based document number for the file, numbered from the bottom of the Court-PASS files table up.';
COMMENT ON COLUMN "search_nycoadocument"."available" IS 'Whether the file is available (False for sealed or not-available files).';
COMMENT ON COLUMN "search_nycoadocument"."docket_entry_id" IS 'The docket entry this document is associated with.';
--
-- Create index search_nyco_filepat_9734a0_idx on field(s) filepath_local of model nycoadocument
--
CREATE INDEX "search_nyco_filepat_9734a0_idx" ON "search_nycoadocument" ("filepath_local");
--
-- Alter unique_together for nycoadocument (1 constraint(s))
--
ALTER TABLE "search_nycoadocument" ADD CONSTRAINT "search_nycoadocument_docket_entry_id_document_1770bb6a_uniq" UNIQUE ("docket_entry_id", "document_number");
ALTER TABLE "search_nycoadocketentry" ADD CONSTRAINT "search_nycoadocketentry_docket_id_page_sequence__28b94570_uniq" UNIQUE ("docket_id", "page", "sequence_number");
ALTER TABLE "search_nycoadocketentry" ADD CONSTRAINT "search_nycoadocketentry_docket_id_791230fc_fk_search_docket_id" FOREIGN KEY ("docket_id") REFERENCES "search_docket" ("id") DEFERRABLE INITIALLY DEFERRED;
CREATE INDEX "search_nycoadocketentry_date_created_34399128" ON "search_nycoadocketentry" ("date_created");
CREATE INDEX "search_nycoadocketentry_date_modified_ade544eb" ON "search_nycoadocketentry" ("date_modified");
CREATE INDEX "search_nycoadocketentry_docket_id_791230fc" ON "search_nycoadocketentry" ("docket_id");
ALTER TABLE "search_nycoadocketmetadata" ADD CONSTRAINT "search_nycoadocketme_docket_id_1b0da300_fk_search_do" FOREIGN KEY ("docket_id") REFERENCES "search_docket" ("id") DEFERRABLE INITIALLY DEFERRED;
CREATE INDEX "search_nycoadocketmetadata_date_created_60250ddd" ON "search_nycoadocketmetadata" ("date_created");
CREATE INDEX "search_nycoadocketmetadata_date_modified_a53a5608" ON "search_nycoadocketmetadata" ("date_modified");
ALTER TABLE "search_nycoadocument" ADD CONSTRAINT "search_nycoadocument_docket_entry_id_99e20288_fk_search_ny" FOREIGN KEY ("docket_entry_id") REFERENCES "search_nycoadocketentry" ("id") DEFERRABLE INITIALLY DEFERRED;
CREATE INDEX "search_nycoadocument_date_created_304b40c2" ON "search_nycoadocument" ("date_created");
CREATE INDEX "search_nycoadocument_date_modified_ef70b44c" ON "search_nycoadocument" ("date_modified");
CREATE INDEX "search_nycoadocument_docket_entry_id_99e20288" ON "search_nycoadocument" ("docket_entry_id");
COMMIT;
